import{_ as e,o as n,c as s,ag as r}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"ASR 模块","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/asr.md","filePath":"guide/architecture/asr.md"}'),o={name:"guide/architecture/asr.md"};function l(i,a,p,t,c,d){return n(),s("div",null,[...a[0]||(a[0]=[r(`<h1 id="asr-模块" tabindex="-1">ASR 模块 <a class="header-anchor" href="#asr-模块" aria-label="Permalink to &quot;ASR 模块&quot;">​</a></h1><p><code>src/lab/asr/</code> — 语音识别，当前支持 <strong>Sherpa-ONNX Paraformer</strong> 和 <strong>Qwen3-ASR（OpenVINO INT8）</strong> 两套引擎。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>asr/</span></span>
<span class="line"><span>├── asr_base_model.py    # ASRBaseModel 抽象基类</span></span>
<span class="line"><span>├── combiner.py          # 句子合并（短间隔句子拼接）</span></span>
<span class="line"><span>├── converter.py         # 通用结果转换工具</span></span>
<span class="line"><span>├── cutter.py            # 句子切分（长停顿处拆句）</span></span>
<span class="line"><span>├── types.py             # 共享类型定义（Sentence / Word）</span></span>
<span class="line"><span>├── sherpa/</span></span>
<span class="line"><span>│   ├── engine.py        # Sherpa-ONNX Paraformer 推理引擎</span></span>
<span class="line"><span>│   ├── probe.py         # 模型探测与验证</span></span>
<span class="line"><span>│   └── utils.py         # 音频预处理工具</span></span>
<span class="line"><span>└── qwen_asr/</span></span>
<span class="line"><span>    ├── engine.py        # Qwen3-ASR OpenVINO 推理引擎（支持 0.6B / 1.7B）</span></span>
<span class="line"><span>    ├── processor.py     # 音频预处理（特征提取）</span></span>
<span class="line"><span>    └── forced_aligner.py # ForcedAligner（词级时间戳对齐，**必须配置**）</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="asrbasemodel" tabindex="-1">ASRBaseModel <a class="header-anchor" href="#asrbasemodel" aria-label="Permalink to &quot;ASRBaseModel&quot;">​</a></h3><p>抽象基类，定义三个接口：</p><ul><li><code>init_model()</code> — 加载模型权重</li><li><code>reload_model()</code> — 热重载</li><li><code>forward(input_path)</code> — 推理</li></ul><p><code>sherpa/engine.py</code> 中的 Sherpa 引擎和 <code>qwen_asr/engine.py</code> 中的 Qwen3-ASR 引擎均实现此接口。</p><h3 id="sherpa-onnx-paraformer" tabindex="-1">Sherpa-ONNX Paraformer <a class="header-anchor" href="#sherpa-onnx-paraformer" aria-label="Permalink to &quot;Sherpa-ONNX Paraformer&quot;">​</a></h3><ul><li>模型：Paraformer-zh（中文）</li><li>后端：sherpa-onnx，推理延迟极低（RTF ≈ 0.007，比实时快 ~140 倍）</li><li>VAD：内置 Silero VAD，支持分段检测</li><li>配置：<code>[asr.sherpa]</code></li></ul><h3 id="qwen3-asr-openvino-int8" tabindex="-1">Qwen3-ASR（OpenVINO INT8） <a class="header-anchor" href="#qwen3-asr-openvino-int8" aria-label="Permalink to &quot;Qwen3-ASR（OpenVINO INT8）&quot;">​</a></h3><ul><li>模型：Qwen3-ASR 0.6B / 1.7B，OpenVINO INT8 量化</li><li>后端：OpenVINO Runtime，CPU 推理（RTF ≈ 0.03–0.33）</li><li>ForcedAligner：<strong>必须配置</strong>，提供词级时间戳对齐能力；未配置或路径不存在时启动即报错</li><li>配置：<code>[asr.qwen_asr]</code></li></ul><p>两个引擎可通过 <code>[package]</code> 开关独立启用，互不干扰，各自注册不同的 API 路由。</p><h3 id="句子后处理" tabindex="-1">句子后处理 <a class="header-anchor" href="#句子后处理" aria-label="Permalink to &quot;句子后处理&quot;">​</a></h3><p>ASR 输出的原始句子需要经过后处理才能用于字幕显示：</p><ol><li><strong>Cutter</strong> — 根据 <code>cut_line</code>（停顿阈值）将长句拆成短句</li><li><strong>Combiner</strong> — 根据 <code>combine_line</code> 将间隔过短的句子合并</li></ol><p>两者互为反向操作，建议只启用其中一个。如果同时启用，需要 <code>combine_line &gt; cut_line</code>。</p><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to &quot;数据结构&quot;">​</a></h3><p>ASR 结果统一为 <code>Sentence</code> 结构（定义在 <code>types.py</code>），包含：</p><ul><li>文本内容</li><li>词级时间戳（<code>Word</code> 列表）</li><li>起止时间</li></ul><p>各引擎的内部输出均会转换为统一的 <code>Sentence</code> 格式，供上层逻辑消费。</p><h2 id="与其他模块的关系" tabindex="-1">与其他模块的关系 <a class="header-anchor" href="#与其他模块的关系" aria-label="Permalink to &quot;与其他模块的关系&quot;">​</a></h2><ul><li><strong>api/routes/asr_sherpa.py</strong> 暴露 Sherpa-ONNX HTTP 接口</li><li><strong>api/routes/asr_qwen.py</strong> 暴露 Qwen3-ASR HTTP 接口</li><li><strong>api/routes/asr_reload.py</strong> 暴露热重载接口</li><li><strong>api/logic/sherpa_asr.py</strong> / <strong>api/logic/qwen_asr.py</strong> 封装推理逻辑</li><li><strong>api/clients/asr_client.py</strong> 提供客户端封装</li></ul>`,24)])])}const g=e(o,[["render",l]]);export{u as __pageData,g as default};
